const email = $input.first().json;

const fromHeader = email.payload?.headers?.find(h => h.name === 'From')?.value || '';
const subjectHeader = email.payload?.headers?.find(h => h.name === 'Subject')?.value || '';

const nameMatch = fromHeader.match(/^(.+?)\s*</);
const emailMatch = fromHeader.match(/<(.+?)>/);

const senderName = nameMatch ? nameMatch[1].trim().replace(/"/g, '') : fromHeader;
const senderEmail = emailMatch ? emailMatch[1] : fromHeader;

const snippet = email.snippet || '';

return [{
  json: {
    sender_name: senderName,
    sender_email: senderEmail,
    subject: subjectHeader,
    body_snippet: snippet,
    message_id: email.id,
    received_at: new Date().toISOString()
  }
}];
